import api from './api';

const getData = (response) => response.data;

// ─── Employees ─────────────────────────────────────────

export const getEmployees = async (params) => {
    const response = await api.get('/hrm/admin/employees', { params });
    return getData(response); // { data: [], pagination: {} }
};

export const getEmployeesByDistrictAndScheme = async (districtId, schemeId) => {
    const params = {};
    if (districtId) params.district_id = districtId;
    if (schemeId) params.scheme_id = schemeId;
    params.is_active = true;
    
    const response = await api.get('/hrm/admin/employees', { params });
    const data = getData(response);
    
    // Return simplified list for dropdown
    return (data?.data?.data || []).map(emp => ({
        employee_id: emp.employee_id,
        employee_code: emp.employee_code,
        full_name: emp.applicant?.personal?.full_name || 'Unknown',
        email: emp.applicant?.email || emp.email,
        scheme_name: emp.scheme?.scheme_name,
        district_name: emp.district?.district_name
    }));
};

export const exportEmployees = async (params, format = 'excel') => {
    const response = await api.get('/hrm/admin/employees/export', {
        params: { ...params, format },
        responseType: 'blob'
    });
    
    // Create download link
    const url = window.URL.createObjectURL(response.data);
    const a = document.createElement('a');
    a.href = url;
    a.download = `employee-records.${format === 'excel' ? 'xlsx' : 'pdf'}`;
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

