export const downloadAttendancePDF = async (params, filename) => {
    const response = await api.get('/hrm/admin/attendance/records/pdf', {
        params,
        responseType: 'blob',
    });
    
    // Create download link
    const url = window.URL.createObjectURL(response.data);
    const a = document.createElement('a');
    a.href = url;
    const defaultFileName = params.employee_id
        ? `attendance-${params.employee_id}.pdf`
        : `attendance-records-${params.month || 'all'}-${params.year || 'all'}.pdf`;
    a.download = filename || defaultFileName;
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

