// payroll
export const getPayslips = async (params = {}) => {
  const response = await api.get("/hrm/admin/payroll-view/payslips", {
    params,
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`,
    },
  });
  return response.data;
};

export const getEmployeePayslip = async (employeeId, month, year) => {
  // Convert month name to number if needed
  const monthNumber = isNaN(month) ? month : parseInt(month);
  const response = await api.get("/hrm/admin/payroll-view/payslip", {
    params: { employee_id: employeeId, month: monthNumber, year },
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`,
    },
  });
  return response.data?.data || response.data;
};

export const downloadEmployeePayslipPDF = async (employeeId, month, year) => {
  // Convert month name to number if needed
  const monthNumber = isNaN(month) ? month : parseInt(month);
  const response = await api.get("/hrm/admin/payroll-view/payslip/export", {
    params: { employee_id: employeeId, month: monthNumber, year },
    headers: {
      Authorization: `Bearer ${localStorage.getItem("token")}`,
    },
    responseType: 'blob' // Important for file download
  });
  
  // Create download link
  const url = window.URL.createObjectURL(new Blob([response.data]));
  const link = document.createElement('a');
  link.href = url;
  link.setAttribute('download', `payslip_${employeeId}_${monthNumber}_${year}.pdf`);
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.URL.revokeObjectURL(url);
};

