// Scheme-wise Attendance
export const getSchemeWiseAttendance = async (filters = {}) => {
    const params = new URLSearchParams();
    if (filters.district_id) params.append('district_id', filters.district_id);
    if (filters.scheme_type) params.append('scheme_type', filters.scheme_type);
    if (filters.date) params.append('date', filters.date);
    
    const response = await api.get(`/hrm/admin/dashboard/scheme-wise-attendance?${params}`);
    return getData(response);
};

// Download Scheme-wise Attendance PDF
export const downloadSchemeWiseAttendancePDF = async (filters = {}) => {
    const params = new URLSearchParams();
    if (filters.district_id) params.append('district_id', filters.district_id);
    if (filters.scheme_type) params.append('scheme_type', filters.scheme_type);
    if (filters.date) params.append('date', filters.date);
    
    const response = await api.get(`/hrm/admin/dashboard/scheme-wise-attendance/pdf?${params}`, {
        responseType: 'blob'
    });
    
    // Create download link
    const url = window.URL.createObjectURL(new Blob([response.data]));
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `scheme-wise-attendance-${filters.date || 'today'}.pdf`);
    document.body.appendChild(link);
    link.click();
    link.remove();
    window.URL.revokeObjectURL(url);
};

